email-sending.example:
import { Resend } from 'resend'

const resend = new Resend(process.env.RESEND_API_KEY)

await resend.emails.send({
  from: 'onboarding@resend.dev',
  to: 'user@example.com',
  subject: 'Hello World',
  html: '<p>Selamat datang!</p>'
})

import nodemailer from 'nodemailer'

const transporter = nodemailer.createTransport({
  service: 'gmail',
  auth: { user: process.env.EMAIL, pass: process.env.PASSWORD }
})

await transporter.sendMail({
  from: '"Nama" <email@example.com>',
  to: 'user@example.com',
  subject: 'Test',
  text: 'Hello'
})

import sgMail from '@sendgrid/mail'
sgMail.setApiKey(process.env.SENDGRID_API_KEY)

await sgMail.send({
  to: 'user@example.com',
  from: 'admin@example.com',
  subject: 'Sending with SendGrid',
  html: '<strong>and easy</strong>'
})

import formData from 'form-data'
import Mailgun from 'mailgun.js'
const mailgun = new Mailgun(formData)
const mg = mailgun.client({ username: 'api', key: process.env.MAILGUN_API_KEY })

await mg.messages.create('sandbox...mailgun.org', {
  from: 'Excited User <mailgun@sandbox...>',
  to: ['user@example.com'],
  subject: 'Hello',
  text: 'Testing some Mailgun awesomeness!'
})

import Plunk from '@plunk/node'
const plunk = new Plunk(process.env.PLUNK_API_KEY)

await plunk.emails.send({
  to: 'user@example.com',
  subject: 'Hello',
  body: '<h1>Welcome!</h1>'
})

email-templates.example:
import { Html, Button, Text } from '@react-email/components'

export function WelcomeEmail({ name }) {
  return (
    <Html>
      <Text>Hello {name},</Text>
      <Button href="https://example.com">Click me</Button>
    </Html>
  )
}

import hbs from 'nodemailer-express-handlebars'
transporter.use('compile', hbs({ viewEngine: 'handlebars', viewPath: './emails' }))

await transporter.sendMail({
  to: 'user@example.com',
  template: 'welcome',
  context: { name: 'Ridho' }
})

